async function main() {
  const pool = mysql.createPool(DATABASE_URL);
  const db = drizzle(pool);
  let inserted = 0, skipped = 0;
  const counts = {};
  for (const evt of NEW_EVENTS) {
    const eventSlug = slugify(evt.title);
    const existing = await db.select({ id: events.id }).from(events).where(eq(events.slug, eventSlug)).limit(1);
    if (existing.length > 0) { skipped++; continue; }
    await db.insert(events).values({ ...evt, slug: eventSlug, imageUrl: null, status: 'published' });
    inserted++;
    counts[evt.category] = (counts[evt.category] || 0) + 1;
  }
  console.log(`Inserted: ${inserted}, Skipped (existing): ${skipped}`);
  console.log('By category:', counts);

  // Archive expired events (start>1mo ago AND (no end OR end>1mo ago))
  const [archiveResult] = await pool.query("UPDATE events SET status='archived' WHERE status='published' AND startDate < DATE_SUB(NOW(), INTERVAL 1 MONTH) AND (endDate IS NULL OR endDate < DATE_SUB(NOW(), INTERVAL 1 MONTH))");
  console.log('Archived expired events:', archiveResult.affectedRows);

  await pool.end();
  process.exit(0);
}
main().catch(e => { console.error(e); process.exit(1); });
